class ContractError extends Error {
  constructor(message: string) {
    super(`[Contract Violation] ${message}`);
    this.name = "ContractError";
  }
}

function contractsEnabled(): boolean {
  return typeof process !== "undefined"
    ? process.env.VDM_CONTRACT_CHECK !== "off"
    : true;
}

function assert(condition: boolean, message: string): asserts condition {
  if (!condition) {
    throw new ContractError(message);
  }
}

// ============================================================
// Type definitions
// ============================================================

/** VDM-SL: UserId = nat1 */
type UserId = number;

function isValidUserId(id: number): boolean {
  return Number.isInteger(id) && id >= 1;
}

/** VDM-SL: Email = seq1 of char */
type Email = string;

function isValidEmail(e: string): boolean {
  return e.length > 0;
}

/** VDM-SL Record: User
 *  inv u == u.age <= 150 */
interface User {
  readonly name: string;
  readonly email: Email;
  readonly age: number;
}

/** 不変条件: inv_User */
function invUser(u: User): boolean {
  return (
    u.name.length > 0 && // seq1 of char
    u.email.length > 0 && // Email = seq1 of char
    Number.isInteger(u.age) &&
    u.age >= 0 && // nat
    u.age <= 150 // inv u == u.age <= 150
  );
}

/** ファクトリ: mk_User */
function mkUser(name: string, email: Email, age: number): User {
  const u: User = { name, email, age };
  if (contractsEnabled()) {
    assert(invUser(u), `User invariant violated: ${JSON.stringify(u)}`);
  }
  return u;
}

