/**
 * VDM-SL: findUser
 *
 * findUser: UserId * map UserId to User -> User
 * findUser(uid, users) == users(uid)
 * pre uid in set dom users
 */
function findUser(uid: UserId, users: Map<UserId, User>): User {
  // Pre-condition
  if (contractsEnabled()) {
    assert(isValidUserId(uid), `Type constraint: uid must be nat1, got ${uid}`);
    assert(users.has(uid), `Pre-condition failed: uid ${uid} not in dom users`);
  }

  // Implementation (from VDM-SL: users(uid))
  const result = users.get(uid)!;

  return result;
}

/**
 * VDM-SL: isAdult
 *
 * isAdult: User -> bool
 * isAdult(u) == u.age >= 18
 */
function isAdult(u: User): boolean {
  if (contractsEnabled()) {
    assert(invUser(u), `Type constraint: u must satisfy User invariant`);
  }

  return u.age >= 18;
}

