/**
 * VDM-SL State: UserDB
 *
 * state UserDB of
 *   users : map UserId to User
 *   nextId : UserId
 * inv mk_UserDB(users, nextId) == nextId not in set dom users
 * init s == s = mk_UserDB({|->}, 1)
 */
class UserDB {
  private _users: Map<UserId, User>;
  private _nextId: UserId;

  constructor() {
    // init s == s = mk_UserDB({|->}, 1)
    this._users = new Map();
    this._nextId = 1;
    this._checkInvariant();
  }

  /** 状態不変条件: nextId not in set dom users */
  private _checkInvariant(): void {
    if (!contractsEnabled()) return;
    assert(
      !this._users.has(this._nextId),
      `State invariant violated: nextId ${this._nextId} already in dom users`
    );
  }

  get users(): ReadonlyMap<UserId, User> {
    return this._users;
  }
  get nextId(): UserId {
    return this._nextId;
  }

  /**
   * VDM-SL Operation: RegisterUser
   *
   * RegisterUser: seq1 of char * Email ==> UserId
   * pre email not in set {users(id).email | id in set dom users}
   * post RESULT in set dom users and users(RESULT).name = name
   */
  registerUser(name: string, email: Email): UserId {
    // Pre-condition
    if (contractsEnabled()) {
      assert(name.length > 0, "Pre-condition failed: name must be non-empty (seq1)");
      assert(
        isValidEmail(email),
        "Pre-condition failed: email must be non-empty (seq1)"
      );
      const existingEmails = new Set(
        [...this._users.values()].map((u) => u.email)
      );
      assert(
        !existingEmails.has(email),
        `Pre-condition failed: email '${email}' already registered`
      );
    }

    // Implementation (from VDM-SL body)
    const uid: UserId = this._nextId;
    this._users.set(uid, mkUser(name, email, 0));
    this._nextId = (this._nextId + 1) as UserId;

    // State invariant
    this._checkInvariant();

    // Post-condition
    if (contractsEnabled()) {
      assert(
        this._users.has(uid),
        `Post-condition failed: RESULT ${uid} not in dom users`
      );
      assert(
        this._users.get(uid)!.name === name,
        `Post-condition failed: users(RESULT).name !== name`
      );
    }

    return uid;
  }
}

